import{_ as e,o as t,c as s,ag as i}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"第 19 章 总结","description":"","frontmatter":{},"headers":[],"relativePath":"ml/conclusion.md","filePath":"ml/conclusion.md","lastUpdated":1777303262000}'),l={name:"ml/conclusion.md"};function n(p,a,o,c,d,r){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="第-19-章-总结" tabindex="-1">第 19 章 总结 <a class="header-anchor" href="#第-19-章-总结" aria-label="Permalink to &quot;第 19 章 总结&quot;">​</a></h1><p>这一章是课程总结，回顾前面学过的主要机器学习方法和实践建议。</p><h2 id="_19-1-总结和致谢" tabindex="-1">19.1 总结和致谢 <a class="header-anchor" href="#_19-1-总结和致谢" aria-label="Permalink to &quot;19.1 总结和致谢&quot;">​</a></h2><p>课程从监督学习开始，介绍了线性回归、逻辑回归、神经网络和支持向量机。</p><p>监督学习部分的核心问题是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>给定带标签训练集，学习输入到输出的映射</span></span></code></pre></div><p>课程还介绍了无监督学习，包括聚类和降维。</p><p>无监督学习的核心问题是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>没有标签时，让算法自动发现数据结构</span></span></code></pre></div><p>后续章节还覆盖了异常检测、推荐系统、大规模机器学习以及 Photo OCR 应用实例。</p><p>除了算法本身，课程反复强调实践方法：</p><ul><li>用训练集、交叉验证集和测试集评估模型。</li><li>通过偏差和方差诊断问题。</li><li>用学习曲线判断是否需要更多数据。</li><li>用误差分析决定下一步。</li><li>用上限分析优化复杂系统。</li></ul><p>这些方法的共同目标是：不要只凭感觉改模型，而是用实验和数据决定下一步。</p>',13)])])}const _=e(l,[["render",n]]);export{u as __pageData,_ as default};
